import os
import pickle
from google.cloud import storage

def get_latest_model(model_path):
    client = storage.Client()
    bucket_name = 'your-bucket-name'
    blobs = client.list_blobs(bucket_name)
    latest_model_version = None
    for blob in blobs:
        if blob.name.startswith(f'{model_path}/'):
            version = int(blob.name.split('/')[-1].split('.')[0])
            if latest_model_version is None or version > latest_model_version:
                latest_model_version = version
    return latest_model_version

def load_latest_model(model_path):
    client = storage.Client()
    bucket_name = 'your-bucket-name'
    model_key = f'{model_path}/latest.pkl'
    blob = client.blob(bucket_name, model_key)
    if blob.exists():
        with open('latest_model.pkl', 'wb') as dest:
            blob.download_to_file(dest)

def load_model(model_path):
    try:
        with open(f'{model_path}.pkl', 'rb') as file:
            return pickle.load(file)
    except Exception as e:
        print(e)

def main():
    model_path = os.environ.get('MODEL_PATH')
    latest_version = get_latest_model(model_path)
    if latest_version is not None:
        load_latest_model(f'{model_path}/{latest_version}')
    else:
        load_model(model_path)
    model = load_model('latest_model.pkl')
    print("Model loaded successfully")

if __name__ == "__main__":
    main()